+/**
+ * Metrics Data Model
+ *
+ * Defines the structure for all metrics collected by Flywheel Gateway.
+ */
+
+/**
+ * Metric types supported by the system.
+ */
+export type MetricType = "counter" | "gauge" | "histogram";
+
+/**
+ * A metric label set.
+ */
+export type Labels = Record<string, string>;
+
+/**
+ * Base metric definition.
+ */
+export interface MetricDefinition {
+  name: string;
+  type: MetricType;
+  description: string;
+  unit?: string;
+  labels?: string[];
+}
+
+/**
+ * A recorded metric value.
+ */
+export interface MetricValue {
+  name: string;
+  type: MetricType;
+  value: number;
+  labels: Labels;
+  timestamp: Date;
+}
+
+/**
+ * Histogram bucket configuration.
+ */
+export interface HistogramBucket {
+  le: number; // less than or equal
+  count: number;
+}
+
+/**
+ * Histogram metric value with distribution data.
+ */
+export interface HistogramValue extends MetricValue {
+  type: "histogram";
+  buckets: HistogramBucket[];
+  sum: number;
+  count: number;
+}
+
+/**
+ * Aggregated metrics for a time period.
+ */
+export interface MetricAggregate {
+  name: string;
+  labels: Labels;
+  period: {
+    start: Date;
+    end: Date;
+  };
+  count: number;
+  sum: number;
+  min: number;
+  max: number;
+  avg: number;
+  p50?: number;
+  p95?: number;
+  p99?: number;
+}
+
+/**
+ * Current snapshot of all system metrics.
+ */
+export interface MetricSnapshot {
+  timestamp: Date;
+  correlationId: string;
+
+  /** Agent metrics */
+  agents: {
+    total: number;
+    byStatus: Record<string, number>;
+    byDriver: Record<string, number>;
+  };
